import React, { useState, useEffect } from "react";
import { LineChart, Line, XAxis, YAxis, CartesianGrid, Tooltip, Legend, ResponsiveContainer } from 'recharts';

export default function MultiDGMasterApp() {
  const [currentUser, setCurrentUser] = useState(null);
  const [users, setUsers] = useState([]);
  const [loginData, setLoginData] = useState({ username: "", password: "" });
  const [dgSets, setDgSets] = useState([]);

  const [form, setForm] = useState({
    name: "", capacity: "", percentage: "", consumption: "", hours: "",
  });

  /* ---------------- FIX 1: Initialization Logic ---------------- */
  useEffect(() => {
    try {
      const savedUsers = JSON.parse(localStorage.getItem("dg_users"));
      const savedDG = JSON.parse(localStorage.getItem("dg_data")) || [];

      if (savedUsers) {
        setUsers(savedUsers);
      } else {
        const defaultUsers = [{ username: "master", password: "0000", role: "master" }];
        setUsers(defaultUsers);
        localStorage.setItem("dg_users", JSON.stringify(defaultUsers));
      }
      setDgSets(savedDG);
    } catch (e) {
      console.error("Failed to load local storage", e);
    }
  }, []);

  const saveDG = (data) => {
    setDgSets(data);
    localStorage.setItem("dg_data", JSON.stringify(data));
  };

  const login = () => {
    const user = users.find(u => u.username === loginData.username && u.password === loginData.password);
    if (user) setCurrentUser(user);
    else alert("Invalid Login (Hint: master / 0000)");
  };

  /* ---------------- FIX 2: Prevent NaN and Calculation Errors ---------------- */
  const addDG = () => {
    // Ensure values are numbers; default to 0 to prevent NaN in calculations
    const cap = parseFloat(form.capacity) || 0;
    const perc = parseFloat(form.percentage) || 0;
    const cons = parseFloat(form.consumption) || 0;
    const hrs = parseFloat(form.hours) || 0;

    if (!form.name || cap <= 0) {
      alert("Please enter a valid Unit Name and Capacity");
      return;
    }

    const availableFuel = (cap * perc) / 100;
    const fuelUsed = hrs * cons;
    const remainingFuel = Math.max(0, availableFuel - fuelUsed);
    // Fixed: Prevent division by zero if consumption is 0
    const backupTime = cons > 0 ? remainingFuel / cons : 0;

    const newEntry = {
      id: Date.now(),
      name: form.name,
      capacity: cap,
      percentage: perc,
      consumption: cons,
      hours: hrs,
      availableFuel: Number(availableFuel.toFixed(2)),
      fuelUsed: Number(fuelUsed.toFixed(2)),
      remainingFuel: Number(remainingFuel.toFixed(2)),
      backupTime: Number(backupTime.toFixed(2)),
      createdBy: currentUser.username,
      date: new Date().toLocaleDateString('en-GB', { day: '2-digit', month: 'short' }),
    };

    saveDG([newEntry, ...dgSets]);
    setForm({ name: "", capacity: "", percentage: "", consumption: "", hours: "" });
  };

  if (!currentUser) {
    return (
      <div style={styles.loginCard}>
        <h2>DG Master Login</h2>
        <input style={styles.input} placeholder="Username" onChange={e => setLoginData({...loginData, username: e.target.value})} />
        <input style={styles.input} type="password" placeholder="Password" onChange={e => setLoginData({...loginData, password: e.target.value})} />
        <button style={styles.btnPrimary} onClick={login}>Login</button>
      </div>
    );
  }

  return (
    <div style={styles.container}>
      <header style={styles.header}>
        <h1>DG Pro Analytics</h1>
        <button style={styles.btnDanger} onClick={() => setCurrentUser(null)}>Logout</button>
      </header>

      {/* --- TREND GRAPH SECTION --- */}
      <div style={styles.graphBox}>
        <h3>Fuel Consumption Trends</h3>
        <div style={{ width: '100%', height: 300 }}>
          {/* FIX 3: Recharts requires a container with height and valid data array */}
          <ResponsiveContainer width="100%" height="100%">
            <LineChart data={[...dgSets].reverse()}>
              <CartesianGrid strokeDasharray="3 3" />
              <XAxis dataKey="date" />
              <YAxis />
              <Tooltip />
              <Legend />
              <Line type="monotone" dataKey="remainingFuel" stroke="#2ecc71" name="Remaining (L)" strokeWidth={2} dot={{r: 4}} />
              <Line type="monotone" dataKey="fuelUsed" stroke="#e74c3c" name="Consumed (L)" strokeWidth={2} />
            </LineChart>
          </ResponsiveContainer>
        </div>
      </div>

      <section style={styles.formGrid}>
        <input style={styles.input} placeholder="Unit Name" value={form.name} onChange={e => setForm({...form, name: e.target.value})} />
        <input style={styles.input} type="number" placeholder="Tank Cap (L)" value={form.capacity} onChange={e => setForm({...form, capacity: e.target.value})} />
        <input style={styles.input} type="number" placeholder="Fuel Level %" value={form.percentage} onChange={e => setForm({...form, percentage: e.target.value})} />
        <input style={styles.input} type="number" placeholder="Cons. (L/hr)" value={form.consumption} onChange={e => setForm({...form, consumption: e.target.value})} />
        <input style={styles.input} type="number" placeholder="Run Hours" value={form.hours} onChange={e => setForm({...form, hours: e.target.value})} />
        <button style={styles.btnSuccess} onClick={addDG}>Save Entry</button>
      </section>

      <div style={styles.list}>
        <h3 style={{marginTop: 20}}>Recent Logs</h3>
        {dgSets.length === 0 && <p style={{color: '#888'}}>No data recorded yet.</p>}
        {dgSets.map(dg => (
          <div key={dg.id} style={styles.card}>
            <div style={{display:'flex', justifyContent:'space-between'}}>
                <strong>{dg.name}</strong>
                <span style={{fontSize: '0.8em', color: '#666'}}>{dg.date}</span>
            </div>
            <div style={{fontSize: '0.9em', marginTop: 5}}>
                {dg.remainingFuel}L Left | <span style={{color: '#e67e22'}}>{dg.backupTime} hrs Backup</span>
            </div>
          </div>
        ))}
      </div>
    </div>
  );
}

const styles = {
  container: { maxWidth: 850, margin: "0 auto", padding: "20px", fontFamily: "'Segoe UI', Tahoma, Geneva, Verdana, sans-serif", color: '#333' },
  loginCard: { width: 320, margin: "100px auto", padding: 30, border: "1px solid #ddd", borderRadius: 12, textAlign: "center", boxShadow: "0 4px 12px rgba(0,0,0,0.1)" },
  header: { display: "flex", justifyContent: "space-between", alignItems: "center", borderBottom: "2px solid #eee", paddingBottom: 15, marginBottom: 20 },
  input: { padding: "12px", marginBottom: "12px", width: "100%", boxSizing: "border-box", borderRadius: 6, border: "1px solid #ccc", outline: 'none' },
  btnPrimary: { width: "100%", padding: 12, backgroundColor: "#3498db", color: "white", border: "none", borderRadius: 6, cursor: "pointer", fontWeight: 'bold' },
  btnSuccess: { padding: 12, backgroundColor: "#2ecc71", color: "white", border: "none", borderRadius: 6, cursor: "pointer", fontWeight: 'bold' },
  btnDanger: { padding: "8px 15px", backgroundColor: "#fdfdfd", color: "#e74c3c", border: "1px solid #e74c3c", borderRadius: 6, cursor: "pointer" },
  graphBox: { backgroundColor: "#fff", padding: 20, borderRadius: 12, margin: "20px 0", border: "1px solid #eee", boxShadow: "0 2px 8px rgba(0,0,0,0.05)" },
  formGrid: { display: "grid", gridTemplateColumns: "repeat(auto-fit, minmax(140px, 1fr))", gap: 12, marginBottom: 25 },
  card: { padding: 15, borderBottom: "1px solid #f0f0f0", backgroundColor: '#fafafa', borderRadius: 8, marginBottom: 10 },
};

